#include <bits/stdc++.h>
using namespace std;
const int maxn=5e4+6e3+5;
int n;
vector<int> g[maxn],dep,sum(2);
void dfs(int u,int fa) {
	sum[dep[u]]++;
	for(auto v:g[u]) {
		if(v==fa) {
			continue;
		}
		dep[v]=dep[u]^1;
		dfs(v,u);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	dep.resize(n+1);
	for(int i=1; i<n; i++) {
		int a,b;
		cin>>a>>b;
		g[a].emplace_back(b);
		g[b].emplace_back(a);
	}
	dfs(1,0);
	cout<<min(sum[0]*2+sum[1],sum[1]*2+sum[0]);
	return 0;
}
